const express = require('express');
const crypto = require('crypto');
const app = express();
const port = 3000;

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// --- In-memory Storage (for demonstration purposes) ---
const clients = [
  {
    client_id: 'myclient',
    client_secret: 'mysecret',
    redirect_uris: ['http://localhost:3001/callback', 'http://localhost:3001/another-callback'],
    scope: 'read write'
  },
  {
    client_id: 'anotherclient',
    client_secret: 'anothersecret',
    redirect_uris: ['http://localhost:3002/callback'],
    scope: 'profile email'
  }
];

const authorizationCodes = new Map(); // code -> { client_id, redirect_uri, scope, user_id, expires_at }
const accessTokens = new Map();       // token -> { client_id, user_id, scope, expires_at }

// --- Constants ---
const AUTHORIZATION_CODE_EXPIRY_SECONDS = 300; // 5 minutes
const ACCESS_TOKEN_EXPIRY_SECONDS = 3600;      // 1 hour

// --- Helper Functions ---
function generateRandomString(length) {
  return crypto.randomBytes(Math.ceil(length / 2)).toString('hex').slice(0, length);
}

function findClient(clientId) {
  return clients.find(c => c.client_id === clientId);
}

// --- OAuth 2.0 Endpoints ---

// Authorization Endpoint
// GET /authorize?response_type=code&client_id=...&redirect_uri=...&scope=...&state=...
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;

  // 1. Validate required parameters
  if (!response_type || !client_id || !redirect_uri) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters: response_type, client_id, redirect_uri' });
  }
  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type', error_description: 'Only "code" response_type is supported' });
  }

  // 2. Validate client
  const client = findClient(client_id);
  if (!client) {
    return res.status(401).json({ error: 'unauthorized_client', error_description: 'Client not found' });
  }

  // 3. Validate redirect_uri
  if (!client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_redirect_uri', error_description: 'Provided redirect_uri is not registered for this client' });
  }

  // 4. (Simulate User Consent)
  // In a real application, you would:
  // - Authenticate the user if not already logged in.
  // - Display a consent screen asking the user to approve the requested scopes for the client.
  // - If user approves, proceed. If user denies, redirect with 'access_denied' error.
  // For this example, we'll assume user consent is always given by a dummy user 'user123'.
  const userId = 'user123'; // Dummy user ID

  // 5. Generate Authorization Code
  const authCode = generateRandomString(32);
  const expiresAt = Date.now() + AUTHORIZATION_CODE_EXPIRY_SECONDS * 1000;

  authorizationCodes.set(authCode, {
    client_id: client_id,
    redirect_uri: redirect_uri,
    scope: scope || client.scope, // Use client's default scope if not provided
    user_id: userId,
    expires_at: expiresAt
  });

  console.log(`Generated auth code for client ${client_id}: ${authCode}`);

  // 6. Redirect back to the client's redirect_uri with the code and state
  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) {
    redirectUrl.searchParams.append('state', state);
  }

  res.redirect(redirectUrl.toString());
});

// Token Endpoint
// POST /token
// grant_type=authorization_code&code=...&redirect_uri=...&client_id=...&client_secret=...
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  // 1. Validate required parameters
  if (!grant_type || !code || !redirect_uri || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
  }
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Only "authorization_code" grant_type is supported' });
  }

  // 2. Validate client credentials
  const client = findClient(client_id);
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client_id or client_secret' });
  }

  // 3. Retrieve and validate authorization code
  const storedAuthCode = authorizationCodes.get(code);

  if (!storedAuthCode) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code is invalid or expired' });
  }
  if (storedAuthCode.expires_at < Date.now()) {
    authorizationCodes.delete(code); // Clean up expired code
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has expired' });
  }

  // 4. Validate that the code belongs to this client and redirect_uri
  if (storedAuthCode.client_id !== client_id || storedAuthCode.redirect_uri !== redirect_uri) {
    // This is a critical security check to prevent code injection
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code does not match client or redirect_uri' });
  }

  // 5. Invalidate the authorization code (one-time use)
  authorizationCodes.delete(code);
  console.log(`Authorization code used and invalidated: ${code}`);

  // 6. Generate Access Token
  const accessToken = generateRandomString(64);
  const expiresAt = Date.now() + ACCESS_TOKEN_EXPIRY_SECONDS * 1000;

  accessTokens.set(accessToken, {
    client_id: storedAuthCode.client_id,
    user_id: storedAuthCode.user_id,
    scope: storedAuthCode.scope,
    expires_at: expiresAt
  });

  console.log(`Generated access token for client ${client_id}: ${accessToken}`);

  // 7. Return Access Token
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: ACCESS_TOKEN_EXPIRY_SECONDS,
    scope: storedAuthCode.scope
    // refresh_token: '...' // Optional: Implement refresh token flow if needed
  });
});

